fixed_code:
// Instead of taking ownership, accept a reference to avoid unnecessary cloning and copying
macro_rules! my_macro {
    ($input:expr) => {{
        let mut tokens = vec![0; $input.len()];
        for (i, c) in $input.chars().enumerate() {
            tokens[i] = c as u8;
        }
        tokens
    }};
}

fn main() {
    let s: &str = "hello";
    let bytes: Vec<u8> = my_macro!(s);
}
